class Solution {
public:
    int compress(vector<char>& chars) {
        if (chars.size() == 1) return 1;
        int write = 0, count = 1;
        for (int read = 1; read < chars.size(); read++) {
            if (chars[read] == chars[read - 1]) {
                count++;
            } else {
                chars[write++] = chars[read - 1];
                if (count > 1) {
                    string countStr = to_string(count);
                    for (char c : countStr) {
                        chars[write++] = c;
                    }
                }
                count = 1;
            }
        }
        chars[write++] = chars.back();
        if (count > 1) {
            string countStr = to_string(count);
            for (char c : countStr) {
                chars[write++] = c;
            }
        }
        return write;
    }
};
